import { useEffect, useState } from 'react';

import API from '../services/api';

import StatsCard from '../components/StatsCard';

function Dashboard() {
  const [stats, setStats] = useState({
    totalLeads: 0,
    admitted: 0,
    counselors: 0,
    pendingFollowups: 0
  });

  useEffect(() => {
    fetchDashboard();
  }, []);

  const fetchDashboard = async () => {
    try {
      const res = await API.get(
        '/dashboard/stats'
      );

      setStats(res.data);
    } catch (error) {
      console.log(error);
    }
  };

  return (
    <div>
      <h1 className="page-title">
        Dashboard
      </h1>

      <p className="page-subtitle">
        Monitor leads, admissions and counselor performance.
      </p>

      <div className="stats-grid">
        <StatsCard
          title="Total Leads"
          value={stats.totalLeads}
        />

        <StatsCard
          title="Admissions"
          value={stats.admitted}
        />

        <StatsCard
          title="Counselors"
          value={stats.counselors}
        />

        <StatsCard
          title="Pending Followups"
          value={stats.pendingFollowups}
        />
      </div>

      <div className="dashboard-grid">
        <div className="dashboard-card">
          <h3 className="card-title">
            Performance Overview
          </h3>

          <div
            style={{
              height: '300px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontWeight: '600',
              fontSize: '18px',
              color: '#6b7280'
            }}
          >
            Analytics & Charts Section
          </div>
        </div>

        <div className="dashboard-card">
          <h3 className="card-title">
            Recent Activity
          </h3>

          <div
            style={{
              display: 'flex',
              flexDirection: 'column',
              gap: '18px'
            }}
          >
            <div>✅ New lead added</div>
            <div>📞 Followup completed</div>
            <div>🎓 Admission confirmed</div>
            <div>📧 Email sent to student</div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
